select count(distinct d.doc_id) from appr_doc d left join appr_line l on d.doc_id = l.doc_id where d.emp_id = #{empId} or (l.emp_id = #{empId} and l.lin_status in ('APP', 'REJ'))
and d.doc_status = #{searchStatus}
and ( d.doc_id like '%' || #{searchKeyword} || '%' or d.doc_title like '%' || #{searchKeyword} || '%' or (select emp_name from employee where emp_id = d.emp_id) like '%' || #{searchKeyword} || '%' )

mapper.update:
update
	appr_doc
set
	doc_status = #{docStatus}
where
	doc_id = #{docId}
